// --- CORE GAME ENGINE ---
let currentQuestions = [];
let currentIndex = 0;
let score = 0;
let timer;
let timeLeft = 30;
let isTestMode = false;
let isLongMode = false;

function initMenu() {
    const topicGrid = document.getElementById('topic-grid');
    const pastPapersGrid = document.getElementById('past-papers-grid');
    if (topicGrid) topicGrid.innerHTML = '';
    if (pastPapersGrid) pastPapersGrid.innerHTML = '';

    const pastPaperTopics = [
        "Topic Area 1: The media industry",
        "Topic Area 2: Factors influencing product design",
        "Topic Area 3: Pre-production planning",
        "Topic Area 4: Distribution considerations"
    ];

    const sortedTopics = Object.keys(questionBank).sort();

    sortedTopics.forEach(topic => {
        if (topic === "Long Questions (6-12 Marks)") return;

        const btn = document.createElement('button');
        btn.innerText = topic;
        btn.onclick = () => startSession(topic);

        if (pastPaperTopics.includes(topic)) {
            btn.className = 'past-paper-btn';
            if (pastPapersGrid) pastPapersGrid.appendChild(btn);
        } else {
            btn.className = 'topic-card';
            if (topicGrid) topicGrid.appendChild(btn);
        }
    });
}

// --- HUB UI FUNCTIONS ---
function toggleNav() {
    document.getElementById("menu-btn").classList.toggle("change");
    document.getElementById("sidebar").classList.toggle("sidebar-open");
    document.getElementById("main-content").classList.toggle("main-push");
}

function toggleDarkMode() {
    const body = document.body;
    body.classList.toggle('dark-mode');
    const isDark = body.classList.contains('dark-mode');
    localStorage.setItem('theme', isDark ? 'dark' : 'light');
    const btn = document.querySelector('.theme-toggle');
    if (btn) btn.innerText = isDark ? '☀️' : '🌙';
}

// Auto-load saved theme
if (localStorage.getItem('theme') === 'dark') {
    document.body.classList.add('dark-mode');
    const btn = document.querySelector('.theme-toggle');
    if (btn) btn.innerText = '☀️';
}

function startSession(mode) {
    isTestMode = (mode === 'TEST');
    isLongMode = (mode === 'Long Questions (6-12 Marks)');
    score = 0;
    currentIndex = 0;

    if (isTestMode) {
        let allQ = [];
        Object.keys(questionBank).forEach(k => {
            if (k !== "Long Questions (6-12 Marks)") allQ = allQ.concat(questionBank[k]);
        });
        currentQuestions = allQ.sort(() => 0.5 - Math.random()).slice(0, 25);
        document.getElementById('topic-display').innerText = "FULL EXAM MODE";
    } else {
        // Do not shuffle long questions to maintain flow, but shuffle MCQs
        if (isLongMode) {
            currentQuestions = [...questionBank[mode]];
        } else {
            currentQuestions = [...questionBank[mode]].sort(() => 0.5 - Math.random());
        }
        document.getElementById('topic-display').innerText = `TOPIC: ${mode.toUpperCase()}`;
    }

    document.getElementById('main-menu').classList.add('hidden');
    document.getElementById('quiz-area').classList.remove('hidden');
    document.getElementById('quiz-area').classList.add('fade-in');

    if (isLongMode) {
        document.getElementById('progress-wrapper').classList.add('hidden');
        document.getElementById('score-display').classList.add('hidden');
        document.getElementById('timer-display').classList.add('hidden');
    } else {
        document.getElementById('progress-wrapper').classList.remove('hidden');
        document.getElementById('header-info').classList.remove('hidden');
        document.getElementById('score-display').classList.remove('hidden');
        document.getElementById('score-display').innerText = "Score: 0";
    }

    nextQuestion();
}

function nextQuestion() {
    if (currentIndex >= currentQuestions.length) {
        showResults(); return;
    }
    const qData = currentQuestions[currentIndex];

    document.getElementById('feedback-area').innerHTML = '';
    document.getElementById('feedback-area').classList.remove('fade-in');
    document.getElementById('continue-btn').classList.add('hidden');

    if (!isLongMode) {
        document.getElementById('progress-bar').style.width = `${((currentIndex + 1) / currentQuestions.length) * 100}%`;
    }

    document.getElementById('question-text').innerText = qData.q;

    // Check if it's a typed question OR the long answer mode
    const isTypedQuestion = isLongMode || qData.type === "typed";

    if (isTypedQuestion) {
        document.getElementById('options-container').classList.add('hidden');
        const longBox = document.getElementById('long-answer-box');
        longBox.classList.remove('hidden');
        longBox.value = ''; // Clear previous answer

        // Add a temporary submit button into the options container area
        const container = document.getElementById('options-container');
        container.innerHTML = `<button id="submit-long-btn" onclick="handleLongAnswer()">SUBMIT & REVEAL MARK SCHEME</button>`;
        container.classList.remove('hidden');

        // Clear timer for typing questions
        clearInterval(timer);
        document.getElementById('timer-display').innerText = "UNTIMED - TAKE YOUR TIME";

    } else {
        document.getElementById('long-answer-box').classList.add('hidden');
        document.getElementById('options-container').classList.remove('hidden');
        renderOptions(qData);
        if (isTestMode) startTimer();
        else document.getElementById('timer-display').innerText = "";
    }

    currentIndex++;
}

function handleLongAnswer() {
    const f = document.getElementById('feedback-area');
    const qData = currentQuestions[currentIndex - 1];

    // Hide the submit button so they can't click it twice
    document.getElementById('submit-long-btn').classList.add('hidden');

    // Format the mark scheme with line breaks
    const formattedMarkScheme = qData.why.replace(/\n/g, '<br>');

    f.innerHTML = `<h3>Self-Assessment</h3><p style="text-align:left; font-size:1.1rem;">${formattedMarkScheme}</p><p style="color:#f39c12; margin-top:15px; font-weight:bold;">Review your typed answer above against the points in the mark scheme.</p>`;
    f.classList.add('fade-in');

    document.getElementById('continue-btn').classList.remove('hidden');
}

function startTimer() {
    clearInterval(timer); timeLeft = 30;
    document.getElementById('timer-display').innerText = `TIME: ${timeLeft}s`;
    timer = setInterval(() => {
        timeLeft--;
        document.getElementById('timer-display').innerText = `TIME: ${timeLeft}s`;
        if (timeLeft <= 0) { clearInterval(timer); handleAnswer(null, currentQuestions[currentIndex - 1].a, currentQuestions[currentIndex - 1].why); }
    }, 1000);
}

function drawAsset(ctx, type) {
    ctx.clearRect(0, 0, 450, 250);
    ctx.strokeStyle = "#2c3e50"; ctx.lineWidth = 2; ctx.lineJoin = "round";
    if (type === "Mood Board") {
        ctx.fillStyle = "#dfe6e9"; ctx.fillRect(20, 20, 160, 100);
        ctx.fillStyle = "#fab1a0"; ctx.fillRect(200, 30, 120, 130);
        ctx.fillStyle = "#74b9ff"; ctx.fillRect(340, 20, 90, 90);
        ctx.fillStyle = "#55efc4"; ctx.fillRect(40, 140, 120, 80);
        ctx.fillStyle = "black"; ctx.font = "bold 16px Arial";
        ctx.fillText("TEXTURES", 210, 180); ctx.fillText("VISUAL STYLE", 320, 130);
    } else if (type === "Mind Map") {
        ctx.beginPath(); ctx.ellipse(225, 120, 80, 45, 0, 0, Math.PI * 2); ctx.stroke();
        ctx.fillStyle = "black"; ctx.font = "bold 30px Arial"; ctx.fillText("A", 212, 130);
        ctx.moveTo(150, 110); ctx.lineTo(60, 60); ctx.moveTo(300, 110); ctx.lineTo(390, 60); ctx.stroke();
    } else if (type === "Work Plan") {
        ctx.fillStyle = "#3498db"; ctx.fillRect(60, 80, 200, 40); ctx.strokeRect(60, 80, 200, 40);
        ctx.beginPath(); ctx.moveTo(360, 80); ctx.lineTo(385, 105); ctx.lineTo(360, 130); ctx.lineTo(335, 105); ctx.closePath();
        ctx.fillStyle = "#f1c40f"; ctx.fill(); ctx.stroke();
        ctx.fillStyle = "black"; ctx.font = "bold 20px Arial"; ctx.fillText("A", 150, 70); ctx.fillText("B", 352, 70);
    } else if (type === "Visualisation" || type === "Wireframe") {
        ctx.strokeRect(100, 40, 250, 170); ctx.moveTo(100, 80); ctx.lineTo(350, 80); ctx.stroke();
        ctx.fillStyle = "black"; ctx.font = "bold 14px Arial"; ctx.fillText("LOGO", 110, 65);
        ctx.font = "bold 35px Arial"; ctx.fillText("A", 210, 160);
    }
}

function renderOptions(qData) {
    const container = document.getElementById('options-container');
    container.innerHTML = '';
    [...qData.options].sort(() => 0.5 - Math.random()).forEach(opt => {
        const btn = document.createElement('button');
        btn.className = 'option-btn'; btn.innerText = opt;
        btn.onclick = () => handleAnswer(opt, qData.a, qData.why);
        container.appendChild(btn);
    });
}

function handleAnswer(choice, correct, why) {
    if (typeof timer !== 'undefined') clearInterval(timer); // Stop the timer

    const btns = document.querySelectorAll('.option-btn');

    // Clean strings just in case there are accidental spaces in the arrays
    const cleanChoice = choice ? choice.trim() : "";
    const cleanCorrect = correct.trim();

    btns.forEach(b => {
        b.disabled = true; // Lock all buttons
        b.style.opacity = "0.5"; // Dim all buttons by default

        const btnText = b.innerText.trim();

        // 1. Always highlight the correct answer in GREEN
        if (btnText === cleanCorrect) {
            b.classList.add('correct-answer');
            b.style.opacity = "1"; // Keep fully visible
        }

        // 2. If they picked the wrong answer, highlight their choice in RED
        if (btnText === cleanChoice && btnText !== cleanCorrect) {
            b.classList.add('wrong-answer');
            b.style.opacity = "1"; // Keep fully visible
        }
    });

    // Update the feedback text area below the buttons
    const f = document.getElementById('feedback-area');
    if (cleanChoice === cleanCorrect) {
        f.innerHTML = `<span style="color:var(--correct); font-weight:bold; font-size:1.2rem;">CORRECT!</span><br><br>` + why;
        score++;
    } else {
        f.innerHTML = `<span style="color:var(--wrong); font-weight:bold; font-size:1.2rem;">INCORRECT.</span><br><br>` + why;
    }

    f.classList.add('fade-in');
    document.getElementById('continue-btn').classList.remove('hidden');

    // Update Score Display
    if (!isLongMode) {
        document.getElementById('score-display').innerText = `Score: ${score}`;
    }
}

function showHint() {
    if (isLongMode) {
        alert("HINT: " + currentQuestions[currentIndex - 1].hint);
    } else {
        alert("HINT: " + currentQuestions[currentIndex - 1].hint);
    }
}

function showMenu() { location.reload(); }

function showResults() {
    document.getElementById('quiz-area').classList.add('hidden');
    document.getElementById('results-area').classList.remove('hidden');

    if (isLongMode) {
        document.getElementById('final-score-text').innerText = `Extended Writing Practice Complete!`;
    } else {
        document.getElementById('final-score-text').innerText = `You scored ${score} / ${currentQuestions.length}`;
    }
}

initMenu();
